	private void format(Function ele, IFormattableDocument document) {
		RosettaGrammarAccess.FunctionElements functionGrammarAccess = grammarAccess.getFunctionAccess();

		document.append(regionFor(ele).keyword(functionGrammarAccess.getFuncKeyword_0()),
				IHiddenRegionFormatter::oneSpace);

		if (ele instanceof FunctionDispatch) {
			FunctionDispatch dispatch = (FunctionDispatch) ele;
			document.surround(regionFor(ele).keyword(functionGrammarAccess.getLeftParenthesisKeyword_1_1_2()),
					IHiddenRegionFormatter::noSpace);
			document.append(
					document.prepend(regionFor(ele).keyword(functionGrammarAccess.getColonKeyword_1_1_4()),
							IHiddenRegionFormatter::noSpace),
					IHiddenRegionFormatter::oneSpace);
			document.format(dispatch.getValue());
			document.surround(regionFor(ele).keyword(functionGrammarAccess.getRightParenthesisKeyword_1_1_6()),
					IHiddenRegionFormatter::noSpace);
		}

		if (ele.getSuperFunction() != null) {
			document.surround(regionFor(ele).keyword(functionGrammarAccess.getExtendsKeyword_2_0()),
					IHiddenRegionFormatter::oneSpace);
		}

		document.prepend(regionFor(ele).keyword(functionGrammarAccess.getColonKeyword_3()),
				IHiddenRegionFormatter::noSpace);
		formatDefinition(ele, document);

		formattingUtil.indentInner(ele, document);

		ele.getReferences().forEach(ref -> {
			document.prepend(ref, IHiddenRegionFormatter::newLine);
			document.format(ref);
		});
		ele.getAnnotations().forEach(ann -> {
			document.prepend(ann, IHiddenRegionFormatter::newLine);
			document.format(ann);
		});

		ISemanticRegion inputsKW = regionFor(ele).keyword(functionGrammarAccess.getInputsKeyword_6_0());
		if (inputsKW != null) {
			document.prepend(inputsKW, IHiddenRegionFormatter::newLine);
			ISemanticRegion inputsColon = document.prepend(
					regionFor(ele).keyword(functionGrammarAccess.getColonKeyword_6_1()),
					IHiddenRegionFormatter::noSpace);
			document.set(
					inputsColon.getNextHiddenRegion(),
					nextHiddenRegion(lastOrNull(ele.getInputs())),
					IHiddenRegionFormatter::indent);
			ele.getInputs().forEach(input -> {
				document.prepend(input, IHiddenRegionFormatter::newLine);
				document.format(input);
			});
		}

		if (ele.getOutput() != null) { // might be null for dispatch functions!
			document.prepend(regionFor(ele).keyword(functionGrammarAccess.getOutputKeyword_7_0()),
					IHiddenRegionFormatter::newLine);
			document.prepend(regionFor(ele).keyword(functionGrammarAccess.getColonKeyword_7_1()),
					IHiddenRegionFormatter::noSpace);
			document.set(
					regionFor(ele).keyword(functionGrammarAccess.getColonKeyword_7_1()).getNextHiddenRegion(),
					nextHiddenRegion(ele.getOutput()),
					IHiddenRegionFormatter::indent);
			document.format(document.prepend(ele.getOutput(), IHiddenRegionFormatter::newLine));
		}

		ele.getShortcuts().forEach(shortcut -> {
			document.prepend(shortcut, f -> f.setNewLines(1, 1, 2));
			document.format(shortcut);
		});
		ele.getConditions().forEach(cond -> {
			document.prepend(cond, f -> f.setNewLines(1, 1, 2));
			document.format(cond);
		});
		ele.getOperations().forEach(op -> {
			document.prepend(op, f -> f.setNewLines(1, 1, 2));
			document.format(op);
		});
		ele.getPostConditions().forEach(cond -> {
			document.prepend(cond, f -> f.setNewLines(1, 1, 2));
			document.format(cond);
		});
	}

