	private void format(RosettaDocReference rosettaRegulatoryReference, IFormattableDocument document) {
		RosettaGrammarAccess.RosettaDocReferenceElements docReferenceGrammarAccess = grammarAccess
				.getRosettaDocReferenceAccess();
		RosettaGrammarAccess.DocumentRationaleElements documentRationaleAccess = grammarAccess
				.getDocumentRationaleAccess();

		ISemanticRegion left = regionFor(rosettaRegulatoryReference).keyword("[");
		ISemanticRegion right = regionFor(rosettaRegulatoryReference).keyword("]");

		document.append(left, IHiddenRegionFormatter::noSpace);
		document.prepend(right, IHiddenRegionFormatter::noSpace);
		document.interior(left, right, IHiddenRegionFormatter::indent);
		formattingUtil.singleSpacesUntil(
				document,
				left.getNextHiddenRegion().getNextHiddenRegion(),
				nextHiddenRegion(rosettaRegulatoryReference.getDocReference()));
		rosettaRegulatoryReference.getRationales().forEach(rationale -> {
			regionFor(rationale).keywords(
					documentRationaleAccess.getRationaleKeyword_0_0(),
					documentRationaleAccess.getRationale_authorKeyword_1_0(),
					documentRationaleAccess.getRationaleKeyword_1_2_0(),
					documentRationaleAccess.getRationale_authorKeyword_0_2_0()).forEach(kw -> {
						document.prepend(kw, IHiddenRegionFormatter::newLine);
						document.append(kw, IHiddenRegionFormatter::oneSpace);
					});
		});
		document.append(
				document.prepend(
						regionFor(rosettaRegulatoryReference)
								.keyword(docReferenceGrammarAccess.getStructured_provisionKeyword_5_0()),
						IHiddenRegionFormatter::newLine),
				IHiddenRegionFormatter::oneSpace);
		document.append(
				document.prepend(
						regionFor(rosettaRegulatoryReference)
								.keyword(docReferenceGrammarAccess.getProvisionKeyword_6_0()),
						IHiddenRegionFormatter::newLine),
				IHiddenRegionFormatter::oneSpace);
		document.prepend(
				regionFor(rosettaRegulatoryReference)
						.keyword(docReferenceGrammarAccess.getReportedFieldReportedFieldKeyword_7_0()),
				IHiddenRegionFormatter::newLine);
	}

