	private void format(RosettaEnumeration ele, IFormattableDocument document) {
		document.append(regionFor(ele).keyword(grammarAccess.getEnumerationAccess().getEnumKeyword_0()),
				IHiddenRegionFormatter::oneSpace);
		document.prepend(regionFor(ele).keyword(grammarAccess.getEnumerationAccess().getColonKeyword_3()),
				IHiddenRegionFormatter::noSpace);
		formatDefinition(ele, document);
		formattingUtil.indentInner(ele, document);

		ele.getReferences().forEach(ref -> {
			document.prepend(ref, IHiddenRegionFormatter::newLine);
			document.format(ref);
		});
		ele.getSynonyms().forEach(syn -> {
			document.prepend(syn, IHiddenRegionFormatter::newLine);
			document.format(syn);
		});
		RosettaEnumValue firstEnumValue = headOrNull(ele.getEnumValues());
		if (firstEnumValue != null) {
			document.format(document.prepend(firstEnumValue, f -> f.setNewLines(1, 2, 2)));
		}
		tail(ele.getEnumValues()).forEach(enumValue -> {
			document.prepend(enumValue, IHiddenRegionFormatter::newLine);
			document.format(enumValue);
		});
	}

