	private void format(RosettaRule ele, IFormattableDocument document) {
		RosettaGrammarAccess.RosettaRuleElements ruleGrammarAccess = grammarAccess.getRosettaRuleAccess();

		ISemanticRegion firstKeyword = regionFor(ele).keyword(ruleGrammarAccess.getReportingKeyword_0_0());
		if (firstKeyword == null) {
			firstKeyword = regionFor(ele).keyword(ruleGrammarAccess.getEligibilityEligibilityKeyword_0_1_0());
		}

		document.append(firstKeyword, IHiddenRegionFormatter::oneSpace);
		document.append(regionFor(ele).keyword(ruleGrammarAccess.getRuleKeyword_1()),
				IHiddenRegionFormatter::oneSpace);
		document.surround(regionFor(ele).keyword(ruleGrammarAccess.getFromKeyword_3_0()),
				IHiddenRegionFormatter::oneSpace);
		document.format(ele.getInput());
		document.append(
				document.prepend(regionFor(ele).keyword(ruleGrammarAccess.getColonKeyword_4()),
						IHiddenRegionFormatter::noSpace),
				IHiddenRegionFormatter::oneSpace);
		formatDefinition(ele, document);

		formattingUtil.indentInner(ele, document);

		ele.getReferences().forEach(ref -> { // TODO: format references
			document.prepend(ref, IHiddenRegionFormatter::newLine);
			document.format(ref);
		});

		document.format(document.prepend(ele.getExpression(), IHiddenRegionFormatter::newLine));
		if (ele.getIdentifier() != null) {
			document.set(
					document.append(
							document.prepend(
									regionFor(ele).keyword(ruleGrammarAccess.getAsKeyword_6_1_1_0_0()),
									IHiddenRegionFormatter::newLine),
							IHiddenRegionFormatter::oneSpace)
							.getPreviousHiddenRegion(),
					regionFor(ele).assignment(ruleGrammarAccess.getIdentifierAssignment_6_1_1_0_1())
							.getNextHiddenRegion(),
					IHiddenRegionFormatter::indent);
		}
	}

