	private void format(ExternalAnnotationSource externalAnnotationSource, IFormattableDocument document) {
		RosettaGrammarAccess.RosettaExternalSynonymSourceElements externalSynonymSourceGrammarAccess = grammarAccess
				.getRosettaExternalSynonymSourceAccess();
		RosettaGrammarAccess.RosettaExternalRuleSourceElements externalRuleSourceGrammarAccess = grammarAccess
				.getRosettaExternalRuleSourceAccess();

		document.surround(
				regionFor(externalAnnotationSource).keyword(externalSynonymSourceGrammarAccess.getSourceKeyword_1()),
				IHiddenRegionFormatter::oneSpace);
		document.surround(
				regionFor(externalAnnotationSource).keyword(externalRuleSourceGrammarAccess.getSourceKeyword_1()),
				IHiddenRegionFormatter::oneSpace);
		document.surround(
				regionFor(externalAnnotationSource).keyword(externalSynonymSourceGrammarAccess.getExtendsKeyword_3_0()),
				IHiddenRegionFormatter::oneSpace);
		document.surround(
				regionFor(externalAnnotationSource).keyword(externalRuleSourceGrammarAccess.getExtendsKeyword_3_0()),
				IHiddenRegionFormatter::oneSpace);

		indentedBraces(externalAnnotationSource, document);
		RosettaExternalClass firstClass = headOrNull(externalAnnotationSource.getExternalClasses());
		if (firstClass != null) {
			document.prepend(firstClass, IHiddenRegionFormatter::newLine);
		}
		tail(externalAnnotationSource.getExternalClasses())
				.forEach(externalClass -> document.prepend(externalClass, f -> f.setNewLines(2)));
		externalAnnotationSource.getExternalClasses().forEach(document::format);

		ISemanticRegion enumsKeyword = regionFor(externalAnnotationSource)
				.keyword(grammarAccess.getExternalAnnotationSourceAccess().getEnumsKeyword_2_0());
		if (enumsKeyword != null) {
			if (externalAnnotationSource.getExternalClasses().isEmpty()) {
				document.prepend(enumsKeyword, IHiddenRegionFormatter::newLine);
			} else {
				document.prepend(enumsKeyword, f -> f.setNewLines(2));
			}
			externalAnnotationSource.getExternalEnums().forEach(externalEnum -> {
				document.prepend(externalEnum, f -> f.setNewLines(2));
				document.format(externalEnum);
			});
		}
	}

